    @Test
    @DisplayName("parseInput(String, String) with real HTML parser returns a Document containing the parsed element")
    public void test_TC09() {
        // Using the real HTML parser to traverse the normal delegation path B0→B1→B3
        Parser parser = Parser.htmlParser();
        String html = "<div>hello</div>";
        String baseUri = "http://test";
        // WHEN: parseInput should delegate to HtmlTreeBuilder.parse and produce a Document
        Document doc = parser.parseInput(html, baseUri);
        // THEN: the document must contain the <div> element with the exact text 'hello'
        Element div = doc.selectFirst("div");
        assertNotNull(div, "Expected a <div> element in the parsed document");
        assertEquals("hello", div.text(), "Div text should match the input content");
    }

    @Test
    @DisplayName("parseInput(String, String) propagates IllegalArgumentException from custom TreeBuilder.parse")
    public void test_TC10() {
        // Inject a TreeBuilder that always throws IllegalArgumentException to hit the exception path B0→B1→B3
        abstract class ExceptionTreeBuilder extends TreeBuilder {
            ExceptionTreeBuilder() {
                // Use default settings from parent abstract class
                super();
            }
            @Override
            public Document parse(Reader input, String baseUri, Parser parser) {
                throw new IllegalArgumentException("parse failed");
            }
            @Override
            public List<Node> parseFragment(Reader input, Element context, String baseUri, Parser parser) {
                // Not used in this test
                return null;
            }
            @Override
            protected void process(Token token) {
                // No-op implementation to satisfy abstract method requirement
            }
            @Override
            public ParseSettings defaultSettings() {
                // Return any non-null settings
                return ParseSettings.preserveCase;
            }
            @Override
            public TreeBuilder newInstance() {
                return new ExceptionTreeBuilder() {};
            }
            @Override
            public boolean isContentForTagData(String name) {
                return false;
            }
            @Override
            public String defaultNamespace() {
                return Parser.NamespaceHtml;
            }
        }

        Parser parser = new Parser(new ExceptionTreeBuilder() {});
        String html = "<invalid>";
        String baseUri = "u";
        // WHEN / THEN: parseInput should propagate the IllegalArgumentException from our TreeBuilder
        IllegalArgumentException ex = assertThrows(
                IllegalArgumentException.class,
                () -> parser.parseInput(html, baseUri),
                "Expected IllegalArgumentException to be thrown when TreeBuilder.parse fails"
        );
        // Verify that the exception message matches our injected failure
        assertEquals("parse failed", ex.getMessage(), "Exception message should propagate the original message");
    }
}
